mapper.select:
select d.id, d.name, d.price, d.image, d.description, d.status, d.create_time, d.update_time,c.name as categoryName from dish d left join category c on d.category_id=c.id
and d.name like concat('%',#{name},'%')
and d.status=#{status}
and d.category_id=#{categoryId}
order by update_time desc
